// ─── Export helper ───
export function getCountry(code: string): CountryConfig | undefined {
  return countries[code.toUpperCase()];
}

export function getDefaultCountry(): CountryConfig {
  return countries['TN']!;
}

export function listCountries(): CountryConfig[] {
  const seen = new Set<string>();
  return Object.values(countries).filter(c => {
    if (seen.has(c.alpha2)) return false;
    seen.add(c.alpha2);
    return true;
  }).sort((a, b) => a.nameEn.localeCompare(b.nameEn));
}

export function getCountriesByRegion(region: string): CountryConfig[] {
  return listCountries().filter(c => c.region === region);
}

export function isFullySupported(country: CountryConfig): boolean {
  return country.supportLevel === 'full';
}

export function getSupportedCountries(): CountryConfig[] {
  return listCountries().filter(isFullySupported);
}

export function countrySupportLevel(code: string): 'full' | 'basic' | 'coming' {
  const c = getCountry(code);
  return c?.supportLevel ?? 'coming';
}
